// 1. Função auxiliar para criar intervalos (ex: de 9 a 16)
const range = (start, end) => Array.from({ length: end - start + 1 }, (_, i) => start + i);

// 2. Definimos a nova distribuição das 56 questões
const materiasMapa = {
    art: range(1, 4),      // 1-4 ARTES
    ing: range(5, 8),      // 5-8 INGLÊS
    port: range(9, 16),    // 9-16 PORTUGUÊS
    edf: range(17, 20),    // 17-20 ED FIS
    mat: range(21, 28),    // 21-28 MATEMÁTICA
    fil: range(29, 32),    // 29-32 FILOSOFIA
    geo: range(33, 36),    // 33-36 GEOGRAFIA
    his: range(37, 40),    // 37-40 HISTORIA
    soc: range(41, 44),    // 41-44 SOCIOLOGIA
    bio: range(45, 48),    // 45-48 BIOLOGIA
    fis: range(49, 52),    // 49-52 FÍSICA
    qui: range(53, 56)     // 53-56 QUÍMICA
};

let corretas = 0;
let erradas = 0;
let totalQuestoesValidas = 56; // NOVO: Começa com 56 e debita a cada 'X'
let anuladas = 0; // Para você saber quantas foram anuladas no total
const statusMaterias = {};

// 3. Inicializamos os contadores de cada matéria
Object.keys(materiasMapa).forEach(m => {
    statusMaterias[m + 'Corretas'] = 0;
    statusMaterias[m + 'Erradas'] = 0;
    statusMaterias[m + 'Validas'] = materiasMapa[m].length; // Quantidade original da matéria
    statusMaterias[m + 'Anuladas'] = 0;
});

// 4. Loop de correção
for (let i = 1; i <= 56; i++) {
    let gabarito = flow.get(`q${i}`);
    let respostaAluno = flow.get(`q${i}Aluno`);

    // Identifica a matéria
    let materia = Object.keys(materiasMapa).find(key => materiasMapa[key].includes(i));

    // Pega o gabarito de forma segura (maiúscula e sem espaços)
    let gabaritoFormatado = typeof gabarito === 'string' ? gabarito.trim().toUpperCase() : gabarito;

    // NOVO: Verifica se o GABARITO é um X (Questão Anulada)
    if (gabaritoFormatado === "X") {
        flow.set(`q${i}Res`, "Anulada");
        totalQuestoesValidas--; // Debita do total geral
        anuladas++;

        if (materia) {
            statusMaterias[materia + 'Validas']--; // Debita do total da matéria
            statusMaterias[materia + 'Anuladas']++;
        }
    }
    // Se a questão NÃO foi anulada, verifica se o aluno acertou
    else if (respostaAluno === gabarito) {
        flow.set(`q${i}Res`, "Correta");
        corretas++;
        if (materia) statusMaterias[materia + 'Corretas']++;
    }
    // Caso contrário, ele errou
    else {
        flow.set(`q${i}Res`, "Errada");
        erradas++;
        if (materia) statusMaterias[materia + 'Erradas']++;
    }
}

// 5. Salva os totais gerais no flow
flow.set('totalCorretas', corretas);
flow.set('totalErradas', erradas);
flow.set('totalQuestoesValidas', totalQuestoesValidas); // Ex: Se 2 anuladas, salva 54
flow.set('totalAnuladas', anuladas);

// 6. Salva os resultados de cada matéria no flow 
Object.keys(statusMaterias).forEach(key => {
    flow.set(key, statusMaterias[key]);
});

return msg;

