msg.topic = `
SELECT 
    a.aluno_id,

    -- MÉDIAS DO ALUNO
    ROUND(a.media_matematica, 2) AS media_matematica,
    ROUND(a.media_linguagens, 2) AS media_linguagens,
    ROUND(a.media_naturezas, 2) AS media_naturezas,
    ROUND(a.media_humanas, 2) AS media_humanas,

    -- MÉDIAS DA SALA (Filtrada pela série com INNER JOIN)
    ROUND(s.mediasala_matematica, 2) AS mediasala_matematica,
    ROUND(s.mediasala_linguagens, 2) AS mediasala_linguagens,
    ROUND(s.mediasala_naturezas, 2) AS mediasala_naturezas,
    ROUND(s.mediasala_humanas, 2) AS mediasala_humanas

FROM 
(
    -- Subquery A: Pega apenas as notas do aluno específico
    SELECT 
        aluno_id,
        AVG(matematica) AS media_matematica,
        AVG(((portugues * 8) + (ingles * 4) + (artes * 4) + (educacao_fisica * 4)) / 20.0) AS media_linguagens,
        AVG(((fisica * 4) + (quimica * 4) + (biologia * 4)) / 12.0) AS media_naturezas,
        AVG(((sociologia * 4) + (filosofia * 4) + (historia * 4) + (geografia * 4)) / 16.0) AS media_humanas
    FROM resultados
    WHERE aluno_id = ? AND simulado_id = ?
    GROUP BY aluno_id
) a
CROSS JOIN
(
    -- Subquery S: Pega a média da sala cruzando com a tabela de alunos para filtrar a série
    SELECT 
        AVG(r.matematica) AS mediasala_matematica,
        AVG(((r.portugues * 8) + (r.ingles * 4) + (r.artes * 4) + (r.educacao_fisica * 4)) / 20.0) AS mediasala_linguagens,
