        AVG(((r.sociologia * 4) + (r.filosofia * 4) + (r.historia * 4) + (r.geografia * 4)) / 16.0) AS mediasala_humanas
    FROM resultados r
    INNER JOIN alunos al ON r.aluno_id = al.id
    WHERE r.simulado_id = ? AND al.serie = ?
) s;
`;

